const express = require('express');
const router = express.Router();
const tasksService = require('./service').service;
router.post('/', (req, res) => {
  if (!req.body.name) return sendError(res, 400, 'BadRequestError', 'Name is required');
  const task = tasksService.createTask(req.body.name);
  res.status(201).json({ task });
});
router.patch('/:taskId', (req, res) => {
  if (!['todo', 'done'].includes(req.body.status)) return sendError(res, 400, 'BadRequestError', 'Invalid status');
  const task = tasksService.updateTaskStatus(req.params.taskId, req.body.status);
  res.json({ task });
});
router.get('/', (req, res) => {
  const tasks = tasksService.getTasks();
  if (req.query.status === 'done') {
    return res.json({ tasks: tasks.filter(task => task.status === 'done') });
  }
  res.json({ tasks });
});
module.exports = { router };

const tasksStore = [];
export function getTasks() {
  return tasksStore;
}
export function createTask(name) {
  const task = { id: randomUUID(), name, status: 'todo' };
tasksStore.push(task);
return task;
}
export function updateTaskStatus(id, status) {
  const taskIndex = tasksStore.findIndex(task => task.id === id);
  if (taskIndex !== -1) {
    tasksStore[taskIndex].status = status;
  }
  return tasksStore.find(task => task.id === id);
}
module.exports = { getTasks, createTask, updateTaskStatus };

const express = require('express');
const router = express.Router();
const membersService = require('./service').service;
router.post('/', (req, res) => {
  if (!req.body.userId || !req.body.role) return sendError(res, 400, 'BadRequestError', 'UserId and role are required');
  const member = membersService.addMember(req.body.userId, req.body.role);
  res.status(201).json({ member });
});
module.exports = { router };

const membersStore = [];
export function getMembers() {
  return membersStore;
}
export function addMember(userId, role) {
  const member = { id: randomUUID(), userId, role };
  membersStore.push(member);
  return member;
}
module.exports = { getMembers, addMember };
const __botEvalMembersDupGuard = module.exports.addMember;
module.exports.addMember = async function addMember(projectId, userId, role) {
  const projectKey = String(projectId || '');
  const userKey = String(userId || '');
  const existing = typeof module.exports.getMembers === 'function' ? await module.exports.getMembers(projectKey) : [];
  if (Array.isArray(existing) && existing.some(member => member && String(member.userId || '') === userKey)) {
    return null;
  }
  if (typeof __botEvalMembersDupGuard === 'function') {
    return __botEvalMembersDupGuard(projectId, userId, role);
  }
  return null;
};

const express = require('express');
const router = express.Router();
const { addComment } = require('./service');
router.post('/', (req, res) => { const comment = addComment(req.body); if (!comment) return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'Invalid input' } }); res.status(201).json(comment); });
module.exports = router;

const { randomUUID } = require('crypto');
const addComment = (data) => {
  if (!data.message) return null;
  const comment = { id: randomUUID(), ...data };
  return comment;
};
module.exports = { addComment };

class CustomError extends Error {
  constructor(code, message) {
    super(message);
    this.code = code;
  }
}
module.exports = { CustomError };
